// frontend/src/components/PlaceCard.js
import React from 'react';

const CROWD_COLORS = {
  Low:    { bg: '#e8f8f2', text: '#085041', dot: '#1D9E75' },
  Medium: { bg: '#fef8e8', text: '#7a4f00', dot: '#d4a017' },
  High:   { bg: '#fdecea', text: '#7a1e1e', dot: '#e53935' },
};

const CAT_EMOJI = {
  mall: '🛍️', cafe: '☕', gym: '💪', restaurant: '🍽️',
};

export default function PlaceCard({ place, prediction, isCheckedIn, onCheckin, onCheckout }) {
  const crowd = prediction?.crowd_level || 'Medium';
  const colors = CROWD_COLORS[crowd] || CROWD_COLORS.Medium;

  const s = {
    card: {
      background: '#fff', borderRadius: '16px', padding: '18px',
      border: `1.5px solid ${isCheckedIn ? '#1D9E75' : '#eee'}`,
      transition: 'all .2s', cursor: 'default',
      boxShadow: isCheckedIn ? '0 0 0 3px #e8f8f2' : '0 2px 12px rgba(0,0,0,0.04)',
    },
    header: { display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', marginBottom: '14px' },
    nameRow: { display: 'flex', alignItems: 'center', gap: '8px' },
    emoji: { fontSize: '20px' },
    name: { fontSize: '15px', fontWeight: '600', color: '#1a1a2e' },
    cat:  { fontSize: '12px', color: '#999', marginTop: '2px' },
    crowdBadge: {
      display: 'flex', alignItems: 'center', gap: '5px', padding: '4px 10px',
      borderRadius: '20px', background: colors.bg, color: colors.text,
      fontSize: '12px', fontWeight: '600',
    },
    dot: { width: '7px', height: '7px', borderRadius: '50%', background: colors.dot },
    metricsGrid: {
      display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '8px', marginBottom: '14px',
    },
    metric: {
      background: '#f7f8fc', borderRadius: '10px', padding: '10px 12px',
    },
    mLabel: { fontSize: '11px', color: '#999', marginBottom: '3px' },
    mValue: { fontSize: '15px', fontWeight: '600', color: '#1a1a2e' },
    mSub:   { fontSize: '11px', color: '#bbb', marginTop: '1px' },
    footer: { display: 'flex', gap: '8px' },
    btnCheckin: {
      flex: 1, padding: '11px', background: isCheckedIn ? '#fdecea' : '#1D9E75',
      color: isCheckedIn ? '#c0392b' : '#fff', border: 'none',
      borderRadius: '10px', fontSize: '14px', fontWeight: '600',
      cursor: 'pointer', transition: 'background .2s',
    },
    btnDetail: {
      padding: '11px 16px', background: '#f4f4f4', color: '#666',
      border: 'none', borderRadius: '10px', fontSize: '13px', cursor: 'pointer',
    },
    checkinStrip: {
      background: '#e8f8f2', borderRadius: '8px', padding: '6px 10px',
      fontSize: '12px', color: '#0f6e56', marginBottom: '10px',
      display: 'flex', alignItems: 'center', gap: '6px',
    },
  };

  return (
    <div style={s.card}>
      {isCheckedIn && (
        <div style={s.checkinStrip}>
          <span>✅</span> Aap yahan hain abhi
        </div>
      )}

      <div style={s.header}>
        <div>
          <div style={s.nameRow}>
            <span style={s.emoji}>{CAT_EMOJI[place.category] || '📍'}</span>
            <span style={s.name}>{place.name}</span>
          </div>
          <div style={s.cat}>
            {place.category?.charAt(0).toUpperCase() + place.category?.slice(1)}
            {place.address ? ` · ${place.address.split(',')[0]}` : ''}
          </div>
        </div>
        <div style={s.crowdBadge}>
          <span style={s.dot} />
          {crowd}
        </div>
      </div>

      <div style={s.metricsGrid}>
        <div style={s.metric}>
          <div style={s.mLabel}>Predicted Crowd</div>
          <div style={s.mValue}>{prediction?.active_users ?? '—'} log</div>
          <div style={s.mSub}>{prediction?.waiting_time ?? 'N/A'}</div>
        </div>
        <div style={s.metric}>
          <div style={s.mLabel}>Estimated Cost</div>
          <div style={s.mValue}>{prediction?.estimated_cost ?? place.avg_cost ? `₹${Math.round(place.avg_cost)}` : '—'}</div>
          <div style={s.mSub}>per visit avg</div>
        </div>
        <div style={s.metric}>
          <div style={s.mLabel}>Best Time</div>
          <div style={{ ...s.mValue, fontSize: '13px' }}>{prediction?.best_time ?? 'Subah'}</div>
        </div>
        <div style={s.metric}>
          <div style={s.mLabel}>Confidence</div>
          <div style={{ ...s.mValue, fontSize: '13px', color: prediction?.confidence === 'high' ? '#1D9E75' : '#d4a017' }}>
            {prediction?.confidence === 'high' ? 'High ✓' : 'Medium'}
          </div>
        </div>
      </div>

      <div style={s.footer}>
        <button
          style={s.btnCheckin}
          onClick={() => isCheckedIn ? onCheckout(place.id) : onCheckin(place.id)}
        >
          {isCheckedIn ? '🚪 Checkout Karo' : '📍 Main Yahan Hoon'}
        </button>
      </div>
    </div>
  );
}
